import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';

// Styled Components
const DashboardContainer = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  padding: 2rem;
`;

const Header = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 16px;
  padding: 1rem 2rem;
  margin-bottom: 2rem;
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
`;

const WelcomeText = styled.div`
  color: white;
  h1 {
    font-size: 1.5rem;
    font-weight: bold;
    margin: 0;
  }
  p {
    margin: 0.5rem 0 0 0;
    opacity: 0.8;
  }
`;

const UserInfo = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
`;

const UserAvatar = styled.img`
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: 2px solid rgba(255, 255, 255, 0.3);
`;

const LogoutButton = styled.button`
  background: rgba(255, 255, 255, 0.2);
  color: white;
  border: 1px solid rgba(255, 255, 255, 0.3);
  padding: 0.5rem 1rem;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 500;
  transition: all 0.2s ease;
  
  &:hover {
    background: rgba(255, 255, 255, 0.3);
    transform: translateY(-1px);
  }
`;

const TestNotice = styled.div`
  background: rgba(254, 243, 199, 0.9);
  color: #92400e;
  padding: 1rem;
  border-radius: 12px;
  margin-bottom: 2rem;
  font-size: 0.875rem;
  text-align: center;
  border: 1px solid rgba(251, 191, 36, 0.5);
`;

const ContentGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const Card = styled.div`
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(10px);
  border-radius: 16px;
  padding: 2rem;
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
  border: 1px solid rgba(255, 255, 255, 0.18);
  transition: transform 0.2s ease;
  
  &:hover {
    transform: translateY(-5px);
  }
  
  h3 {
    color: white;
    font-size: 1.25rem;
    font-weight: bold;
    margin: 0 0 1rem 0;
  }
  
  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.6;
    margin: 0;
  }
`;

const ActionButton = styled.button`
  background: rgba(255, 255, 255, 0.2);
  color: white;
  border: 1px solid rgba(255, 255, 255, 0.3);
  padding: 0.5rem 1rem;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.875rem;
  margin-top: 1rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: rgba(255, 255, 255, 0.3);
    transform: translateY(-1px);
  }
`;

const LoadingSpinner = styled.div`
  display: flex;
  justify-content: center;
  align-items: center;
  height: 200px;
  
  .spinner {
    width: 40px;
    height: 40px;
    border: 4px solid rgba(255, 255, 255, 0.3);
    border-top: 4px solid white;
    border-radius: 50%;
    animation: spin 1s linear infinite;
  }
  
  @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
  }
`;

const StatCard = styled(Card)`
  text-align: center;
  
  .stat-number {
    font-size: 2.5rem;
    font-weight: bold;
    color: white;
    margin-bottom: 0.5rem;
  }
  
  .stat-label {
    color: rgba(255, 255, 255, 0.8);
    font-size: 0.875rem;
  }
`;

const ActivityList = styled.div`
  .activity-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    
    &:last-child {
      border-bottom: none;
    }
  }
  
  .activity-icon {
    width: 32px;
    height: 32px;
    background: rgba(255, 255, 255, 0.2);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.875rem;
  }
  
  .activity-text {
    flex: 1;
    font-size: 0.875rem;
  }
  
  .activity-time {
    font-size: 0.75rem;
    opacity: 0.7;
  }
`;

const DashboardPageTest = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalTasks: 0,
    completedTasks: 0,
    activeProjects: 0,
    teamMembers: 0
  });
  const [activities, setActivities] = useState([]);

  useEffect(() => {
    // 테스트용 사용자 정보 로드
    const loadTestData = () => {
      const savedUser = localStorage.getItem('user');
      const token = localStorage.getItem('accessToken');
      
      if (!token || !savedUser) {
        navigate('/login-test');
        return;
      }

      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        
        // 가짜 통계 데이터 생성
        setStats({
          totalTasks: Math.floor(Math.random() * 50) + 10,
          completedTasks: Math.floor(Math.random() * 30) + 5,
          activeProjects: Math.floor(Math.random() * 8) + 2,
          teamMembers: Math.floor(Math.random() * 15) + 3
        });
        
        // 가짜 활동 데이터 생성
        const testActivities = [
          { icon: '📝', text: '새로운 작업을 생성했습니다', time: '방금 전' },
          { icon: '✅', text: '프로젝트 A를 완료했습니다', time: '2시간 전' },
          { icon: '👥', text: '팀 미팅에 참석했습니다', time: '4시간 전' },
          { icon: '📊', text: '월간 보고서를 업로드했습니다', time: '1일 전' },
          { icon: '🚀', text: '새로운 기능을 배포했습니다', time: '2일 전' }
        ];
        setActivities(testActivities);
        
      } catch (error) {
        console.error('사용자 데이터 로드 오류:', error);
        navigate('/login-test');
      } finally {
        setTimeout(() => setLoading(false), 1000); // 로딩 시뮬레이션
      }
    };

    loadTestData();
  }, [navigate]);

  const handleLogout = () => {
    // 로컬 스토리지 정리
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
    localStorage.removeItem('user');
    
    // 로그인 페이지로 이동
    navigate('/login-test');
  };

  const handleRefreshData = () => {
    setLoading(true);
    
    // 데이터 새로고침 시뮬레이션
    setTimeout(() => {
      setStats({
        totalTasks: Math.floor(Math.random() * 50) + 10,
        completedTasks: Math.floor(Math.random() * 30) + 5,
        activeProjects: Math.floor(Math.random() * 8) + 2,
        teamMembers: Math.floor(Math.random() * 15) + 3
      });
      setLoading(false);
    }, 1500);
  };

  if (loading) {
    return (
      <DashboardContainer>
        <LoadingSpinner>
          <div className="spinner"></div>
        </LoadingSpinner>
      </DashboardContainer>
    );
  }

  return (
    <DashboardContainer>
      <Header>
        <WelcomeText>
          <h1>환영합니다! {user?.name || '사용자'}님</h1>
          <p>테스트 대시보드에 오신 것을 환영합니다.</p>
        </WelcomeText>
        
        <UserInfo>
          {user?.picture && (
            <UserAvatar 
              src={user.picture} 
              alt={user.name || '사용자'} 
            />
          )}
          <div style={{ color: 'white' }}>
            <div style={{ fontWeight: 'bold' }}>{user?.name || '이름 없음'}</div>
            <div style={{ fontSize: '0.875rem', opacity: 0.8 }}>
              {user?.email || '이메일 없음'}
            </div>
          </div>
          <LogoutButton onClick={handleLogout}>
            로그아웃
          </LogoutButton>
        </UserInfo>
      </Header>

      <TestNotice>
        🧪 이것은 테스트 버전입니다. 모든 데이터는 가짜 데이터이며 실제 API와 연결되지 않습니다.
      </TestNotice>

      {/* 통계 카드들 */}
      <ContentGrid>
        <StatCard>
          <div className="stat-number">{stats.totalTasks}</div>
          <div className="stat-label">전체 작업</div>
        </StatCard>
        
        <StatCard>
          <div className="stat-number">{stats.completedTasks}</div>
          <div className="stat-label">완료된 작업</div>
        </StatCard>
        
        <StatCard>
          <div className="stat-number">{stats.activeProjects}</div>
          <div className="stat-label">진행 중인 프로젝트</div>
        </StatCard>
        
        <StatCard>
          <div className="stat-number">{stats.teamMembers}</div>
          <div className="stat-label">팀 멤버</div>
        </StatCard>
      </ContentGrid>

      <ContentGrid>
        <Card>
          <h3>사용자 정보</h3>
          <p>
            <strong>이름:</strong> {user?.name || 'N/A'}<br/>
            <strong>이메일:</strong> {user?.email || 'N/A'}<br/>
            <strong>가입일:</strong> {user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : 'N/A'}<br/>
            <strong>사용자 ID:</strong> {user?.id || 'N/A'}
          </p>
          <ActionButton onClick={() => alert('프로필 수정 기능 (준비 중)')}>
            프로필 수정
          </ActionButton>
        </Card>

        <Card>
          <h3>최근 활동</h3>
          <ActivityList>
            {activities.map((activity, index) => (
              <div key={index} className="activity-item">
                <div className="activity-icon">{activity.icon}</div>
                <div className="activity-text">{activity.text}</div>
                <div className="activity-time">{activity.time}</div>
              </div>
            ))}
          </ActivityList>
        </Card>

        <Card>
          <h3>프로젝트 현황</h3>
          <p>
            현재 {stats.activeProjects}개의 프로젝트가 진행 중입니다.<br/>
            이번 주에 {Math.floor(Math.random() * 5) + 1}개의 작업이 완료되었습니다.<br/>
            전체 진행률: {Math.floor((stats.completedTasks / stats.totalTasks) * 100)}%
          </p>
          <ActionButton onClick={() => alert('프로젝트 관리 페이지 (준비 중)')}>
            프로젝트 보기
          </ActionButton>
        </Card>

        <Card>
          <h3>시스템 정보</h3>
          <p>
            <strong>로그인 시간:</strong> {new Date().toLocaleString()}<br/>
            <strong>마지막 활동:</strong> 방금 전<br/>
            <strong>세션 상태:</strong> 활성<br/>
            <strong>권한 레벨:</strong> 사용자
          </p>
          <ActionButton onClick={handleRefreshData}>
            데이터 새로고침
          </ActionButton>
        </Card>
      </ContentGrid>
    </DashboardContainer>
  );
};

export default DashboardPageTest;
